import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/jobs/all")
      .then(res => setJobs(res.data));
  }, []);

  const acceptJob = async (id) => {
    await axios.put(`http://localhost:5000/api/jobs/accept/${id}`);
    window.location.reload();
  };

  const rejectJob = async (id) => {
    await axios.put(`http://localhost:5000/api/jobs/reject/${id}`);
    window.location.reload();
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1>Job Requests</h1>

        <div style={styles.grid}>

          {jobs.map(job => (

            <div key={job._id} style={styles.card}>

              <h2>{job.workerName}</h2>

              <p><strong>Work:</strong> {job.workType}</p>

              <p><strong>Price:</strong> ₹{job.price}</p>

              <p><strong>Status:</strong> {job.status}</p>

              <p>
                <strong>Time Slots:</strong><br/>
                {job.timeSlots?.join(", ")}
              </p>

              <div style={styles.btnRow}>

                <button
                  style={styles.acceptBtn}
                  onClick={() => acceptJob(job._id)}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => rejectJob(job._id)}
                >
                  Reject
                </button>

              </div>

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {
  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "16px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.08)"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "15px"
  },

  acceptBtn: {
    background: "#22c55e",
    color: "white",
    border: "none",
    padding: "10px 16px",
    borderRadius: "8px",
    cursor: "pointer"
  },

  rejectBtn: {
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "10px 16px",
    borderRadius: "8px",
    cursor: "pointer"
  }
};
